# Claude Code Account Switcher — bash integration
# Generated by: eval "$(claude-acc init bash)"

__claude_acc_activate() {
    eval "$('__CLAUDE_ACC_BIN__' activate --shell posix)"
}

__claude_acc_prompt_hook() {
    if [[ "$PWD" != "$__CLAUDE_ACC_PREV_DIR" ]]; then
        __claude_acc_activate
        __CLAUDE_ACC_PREV_DIR="$PWD"
    fi
}
PROMPT_COMMAND="__claude_acc_prompt_hook${PROMPT_COMMAND:+;$PROMPT_COMMAND}"

# Activate for current directory on shell startup
__claude_acc_activate

# Completions
_claude_acc_complete() {
    local cur prev
    cur="${COMP_WORDS[COMP_CWORD]}"
    prev="${COMP_WORDS[COMP_CWORD-1]}"
    if [[ $COMP_CWORD -eq 1 ]]; then
        COMPREPLY=($(compgen -W "list add login remove default reset link unlink links status help" -- "$cur"))
    elif [[ $COMP_CWORD -eq 2 ]]; then
        case "$prev" in
            login|remove)
                COMPREPLY=($(compgen -W "$('__CLAUDE_ACC_BIN__' completions accounts)" -- "$cur"))
                ;;
            default|link)
                COMPREPLY=($(compgen -W "default $('__CLAUDE_ACC_BIN__' completions accounts)" -- "$cur"))
                ;;
        esac
    fi
}
complete -F _claude_acc_complete claude-acc
